  ): Promise<FeatureFlagActivityResponse> {
    return request(
      `${projBase}/feature_flags/${id}/activity/?limit=${limit ?? 10}`,
      { method: 'GET' },
    ) as Promise<FeatureFlagActivityResponse>;
  }

  return {
    request,
    listDashboards,
    createDashboard,
    getDashboard,
    patchDashboard,
    createInsight,
    createInsightOnDashboard,
    getInsightByShortId,
    runQuery,
    listFeatureFlags,
    getFeatureFlag,
    patchFeatureFlag,
    createFeatureFlag,
    getFeatureFlagActivity,
  };
}

